script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const apiKey = process.env.PLATFORM_API_KEY;
  const baseUrl = process.env.APP_BASE_URL;
  if (!apiKey || !baseUrl) { console.error('PLATFORM_API_KEY or APP_BASE_URL missing'); process.exit(1); }
  const ns = input.namespace;
  if (!ns) { console.error('namespace missing from trigger input'); process.exit(1); }
  const res = await fetch(`${baseUrl}/api/users/members?namespace=${encodeURIComponent(ns)}`, {
    headers: { 'X-Api-Key': apiKey, Accept: 'application/json' },
  });
  if (!res.ok) { console.error(`Failed to fetch members: ${res.status}`); process.exit(1); }
  const data = await res.json();
  const options = (data.members || []).map(m => ({
    id: m.uid,
    label: m.displayName || m.email || m.uid,
    email: m.email || '',
    avatarUrl: m.avatarUrl || '',
  }));
  writeFileSync('/output/result.json', JSON.stringify({ options, summary: `Fetched ${options.length} member(s) from ${ns}` }));
  console.log(`Fetched ${options.length} member(s) from ${ns}`);
} catch (err) {
  console.error('fetch_members crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const rows = input.steps?.select_team?.rows || [];
  const fetched = input.steps?.fetch_members?.options || [];
  const includedIds = new Set(rows.filter(r => r.values?.include === 'yes').map(r => r.itemId));
  const teamMembers = fetched.filter(m => includedIds.has(m.id)).map(m => ({ userId: m.id, email: m.email, name: m.label }));
  if (teamMembers.length === 0) { console.error('No members selected'); process.exit(1); }
  const hours = Number(input.durationHours);
  if (!Number.isFinite(hours) || hours <= 0) { console.error('durationHours must be a positive number'); process.exit(1); }
  const deadline = new Date(Date.now() + hours * 3600000).toISOString();
  writeFileSync('/output/result.json', JSON.stringify({ teamMembers, deadline, summary: `Selected ${teamMembers.length} member(s), deadline ${deadline}` }));
  console.log(`Selected ${teamMembers.length} member(s), deadline ${deadline}`);
} catch (err) {
  console.error('prepare crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const spawned = input.steps?.gather_profiles?.spawned || [];
  const teamMembers = input.steps?.prepare?.teamMembers || [];
  const apiKey = process.env.PLATFORM_API_KEY;
  const baseUrl = process.env.APP_BASE_URL;
  if (!apiKey || !baseUrl) { console.error('PLATFORM_API_KEY or APP_BASE_URL missing'); process.exit(1); }
  const profiles = [];
  for (const entry of spawned) {
    const member = (entry.itemIndex != null) ? teamMembers[entry.itemIndex] : null;
    let pv = {};
    try {
      const res = await fetch(`${baseUrl}/api/processes/${entry.instanceId}`, {
        headers: { 'X-Api-Key': apiKey, Accept: 'application/json' },
      });
      if (res.ok) { const inst = await res.json(); pv = inst.variables?.provide_profile?.paramValues || {}; }
      else { console.error(`Failed to fetch instance ${entry.instanceId}: ${res.status}`); }
    } catch (err) { console.error(`Error fetching instance ${entry.instanceId}: ${err?.message || err}`); }
    profiles.push({
      userId: member?.userId || null,
      name: member?.name || null,
      email: member?.email || null,
      strengths: pv.strengths || null,
      weaknesses: pv.weaknesses || null,
      interests: pv.interests || null,
      availability: pv.availability || null,
      responded: Boolean(pv.strengths),
    });
  }
  const respondedCount = profiles.filter(p => p.responded).length;
  writeFileSync('/output/result.json', JSON.stringify({ profiles, profileCount: respondedCount, totalSpawned: spawned.length, summary: `Collected ${respondedCount} of ${spawned.length} profiles` }));
  console.log(`Collected ${respondedCount} of ${spawned.length} profiles`);
} catch (err) {
  console.error('collect_profiles crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

agent.prompt:
# Match Kaggle Competitions to the Team

Read `/output/input.json`:
- `steps.collect_profiles.profiles[]` - each `{ userId, name, strengths, weaknesses, interests, availability, responded }`.
- `steps.fetch_competitions.competitions[]` - each `{ ref, title, category, deadline, tags, description, reward }`.

## Task
Rank the competitions by how well they fit the team's aggregate strengths and interests. Produce a shortlist of the 3-5 best matches. For each, explain the fit in one or two sentences grounded in the actual profiles (cite real strengths/interests). Do not invent competitions or profiles.

## OUTPUT CONTRACT (MANDATORY)
1) Write result JSON to `/output/result.json`.
2) Your FINAL message must be ONLY: {"output_file": "/output/result.json", "summary": "..."}

result.json shape:
{
  "options": [
    {
      "label": "<competition title>",
      "description": "<one-line fit summary>",
      "value": { "ref": "<competition ref>", "title": "<title>", "category": "<category>", "deadline": "<deadline>", "fitRationale": "<why it fits the team>" }
    }
  ],
  "summary": "<one sentence overview of the shortlist>"
}
